// CONFIGURACIÓN DE PAGOS — sub-tabs
// ═══════════════════════════════════════════════════════════════════════════
function ConfiguracionPagos() {
  const [subtab, setSubtab] = useState("tarifario");
  return (
    <div className="pg" style={{ maxWidth: 1200 }}>
      <div style={{ marginBottom: 16 }}>
        <div className="sec-title">Configuración</div>
        <div className="sec-sub">Reglas y valores que alimentan el motor de cálculo de pagos</div>
      </div>
      <div style={{ display: "flex", gap: 6, marginBottom: 16, flexWrap: "wrap" }}>
        {[
          { id: "tarifario", l: "Tarifario Base" },
          { id: "especiales", l: "Tarifas Especiales" },
          { id: "zonas", l: "Mapeo SC ↔ Zonas" },
          { id: "auxiliares", l: "Matriz Auxiliares" },
          { id: "ns", l: "Reglas NS" },
        ].map(t => (
          <button key={t.id} onClick={() => setSubtab(t.id)}
            style={{ padding: "7px 14px", borderRadius: 4, border: `1px solid ${subtab === t.id ? "#1a3a6b" : "#e4e7ec"}`,
              background: subtab === t.id ? "#1a3a6b" : "#fff", color: subtab === t.id ? "#fff" : "#475569",
              fontSize: 12, fontWeight: 600, cursor: "pointer" }}>
            {t.l}
          </button>
        ))}
      </div>
      {subtab === "tarifario" && <ConfigTarifario />}
      {subtab === "especiales" && <ConfigTarifasEspeciales />}
      {subtab === "zonas" && <ConfigZonas />}
      {subtab === "auxiliares" && <ConfigMatrizAuxiliares />}
      {subtab === "ns" && <ConfigReglasNS />}
    </div>
  );
}

// ─── Config: Tarifario Base ────────────────────────────────────────────────
function ConfigTarifario() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { cargar(); }, []);
  const cargar = async () => {
    setLoading(true);
    try {
      const { data: d } = await sb.from("tarifario_mx").select("*").order("zona").order("tipologia").order("tramo_km");
      setData(d || []);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  if (loading) return <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>Cargando...</div>;

  const zonas = ["L1", "L2", "L3", "L4"];
  const tipologias = ["Large Van", "Small Van", "Car"];
  const tramos = ["0-100", "101-150", "151-200", "201-250", "251+"];

  return (
    <div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>Tarifario Base MELI MX</div>
        <div style={{ fontSize: 11, color: "#94a3b8" }}>{data.length} tarifas · 4 zonas × 3 tipologías × 5 tramos · MXN</div>
      </div>
      {zonas.map(z => (
        <div key={z} style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: "#1a3a6b", marginBottom: 10 }}>Zona {z}</div>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Tipología</th>
                {tramos.map(t => <th key={t} style={{ padding: "6px 10px", textAlign: "right", fontSize: 10, color: "#64748b", fontWeight: 600 }}>{t} km</th>)}
              </tr>
            </thead>
            <tbody>
              {tipologias.map(tipo => {
                const filas = data.filter(d => d.zona === z && d.tipologia === tipo);
                if (filas.length === 0) return null;
                return (
                  <tr key={tipo} style={{ borderBottom: "1px solid #f0f0f0" }}>
                    <td style={{ padding: "6px 10px", fontWeight: 600 }}>{tipo}</td>
                    {tramos.map(tr => {
                      const f = filas.find(x => x.tramo_km === tr);
                      return (
                        <td key={tr} style={{ padding: "6px 10px", textAlign: "right", color: f ? "#1f2937" : "#cbd5e1" }}>
                          {f ? `$${f.monto.toLocaleString("es-MX")}` : "—"}
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      ))}
    </div>
  );
}

// ─── Config: Tarifas Especiales ────────────────────────────────────────────
function ConfigTarifasEspeciales() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { cargar(); }, []);
  const cargar = async () => {
    setLoading(true);
    try {
      const { data: d } = await sb.from("tarifas_especiales_mx").select("*").order("driver_name").order("zona").order("tramo_km");
      setData(d || []);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  if (loading) return <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>Cargando...</div>;

  const drivers = [...new Set(data.map(d => d.driver_name))];

  return (
    <div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>Tarifas Especiales por Chofer</div>
        <div style={{ fontSize: 11, color: "#94a3b8" }}>{drivers.length} choferes con tarifa custom · {data.length} reglas totales</div>
      </div>
      {drivers.map(driver => {
        const tarifas = data.filter(d => d.driver_name === driver);
        return (
          <div key={driver} style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: "#1a3a6b", marginBottom: 10 }}>{driver}</div>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
              <thead>
                <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                  <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Tipología</th>
                  <th style={{ padding: "6px 10px", textAlign: "center", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Zona</th>
                  <th style={{ padding: "6px 10px", textAlign: "center", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Tramo km</th>
                  <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Monto</th>
                </tr>
              </thead>
              <tbody>
                {tarifas.map(t => (
                  <tr key={t.id} style={{ borderBottom: "1px solid #f0f0f0" }}>
                    <td style={{ padding: "6px 10px" }}>{t.tipologia}</td>
                    <td style={{ padding: "6px 10px", textAlign: "center" }}>{t.zona || "—"}</td>
                    <td style={{ padding: "6px 10px", textAlign: "center" }}>{t.tramo_km}</td>
                    <td style={{ padding: "6px 10px", textAlign: "right", fontWeight: 600 }}>${t.monto.toLocaleString("es-MX")}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        );
      })}
    </div>
  );
}

// ─── Config: Mapeo SC ↔ Zonas (CRUD + detector de huérfanos) ───────────────
function ConfigZonas() {
  const [data, setData] = useState([]);
  const [huerfanos, setHuerfanos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingHuerfanos, setLoadingHuerfanos] = useState(true);
  const [filtroZona, setFiltroZona] = useState("todas");
  const [busqueda, setBusqueda] = useState("");

  // Modal de edición/creación
  const [modal, setModal] = useState(null); // { mode: 'create'|'edit', data: {...} }
  const [guardando, setGuardando] = useState(false);

  useEffect(() => { cargar(); detectarHuerfanos(); }, []);

  const cargar = async () => {
    setLoading(true);
    try {
      const { data: d } = await sb.from("sc_zonas_mx").select("*").order("zona").order("service_center_id");
      setData(d || []);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  const detectarHuerfanos = async () => {
    setLoadingHuerfanos(true);
    try {
      // Traer SCs distintos de viajes MX en últimos 7 días vs sc_zonas_mx
      const fechaDesde = new Date();
      fechaDesde.setDate(fechaDesde.getDate() - 7);
      const fdStr = fechaDesde.toISOString().split("T")[0];

      const [vRes, zRes] = await Promise.all([
        sb.from("viajes").select("tms_raw, fecha_salida")
          .eq("pais", "MX")
          .gte("fecha_salida", fdStr),
        sb.from("sc_zonas_mx").select("service_center_id"),
      ]);

      const viajes = vRes.data || [];
      const zonasMapeadas = new Set((zRes.data || []).map(z => z.service_center_id));

      // Agrupar por SC
      const map = {};
      for (const v of viajes) {
        const sc = v.tms_raw?.["Service center"];
        if (!sc) continue;
        if (zonasMapeadas.has(sc)) continue;
        if (!map[sc]) map[sc] = { sc, viajes: 0, primera: v.fecha_salida, ultima: v.fecha_salida };
        map[sc].viajes++;
        if (v.fecha_salida < map[sc].primera) map[sc].primera = v.fecha_salida;
        if (v.fecha_salida > map[sc].ultima) map[sc].ultima = v.fecha_salida;
      }
      const lista = Object.values(map).sort((a, b) => b.viajes - a.viajes);
      setHuerfanos(lista);
    } catch (e) { console.error(e); }
    setLoadingHuerfanos(false);
  };

  const abrirCrear = (scIdPreset = "") => {
    setModal({
      mode: "create",
      data: {
        service_center_id: scIdPreset,
        zona: "L1",
        ciudad: "",
        observaciones: "",
        vigente_desde: new Date().toISOString().split("T")[0],
      }
    });
  };

  const abrirEditar = (sc) => {
    setModal({
      mode: "edit",
      data: { ...sc, vigente_desde: sc.vigente_desde || new Date().toISOString().split("T")[0] }
    });
  };

  const cerrarModal = () => setModal(null);

  const guardar = async () => {
    if (!modal) return;
    const d = modal.data;
    if (!d.service_center_id?.trim()) { alert("El ID del Service Center es obligatorio"); return; }
    if (!["L1", "L2", "L3", "L4"].includes(d.zona)) { alert("Zona inválida"); return; }

    setGuardando(true);
    try {
      const payload = {
        service_center_id: d.service_center_id.trim().toUpperCase(),
        zona: d.zona,
        ciudad: d.ciudad?.trim() || null,
        observaciones: d.observaciones?.trim() || null,
        vigente_desde: d.vigente_desde,
        actualizado_por: "brain",
      };

      if (modal.mode === "create") {
        // Verificar duplicado
        const ya = data.find(x => x.service_center_id === payload.service_center_id);
        if (ya) { alert(`Ya existe el SC ${payload.service_center_id}. Usá "Editar" en su lugar.`); setGuardando(false); return; }
        payload.creado_por = "brain";
        const { error } = await sb.from("sc_zonas_mx").insert(payload);
        if (error) throw error;
      } else {
        const { error } = await sb.from("sc_zonas_mx").update(payload).eq("id", d.id);
        if (error) throw error;
      }

      cerrarModal();
      await cargar();
      await detectarHuerfanos();
    } catch (e) {
      console.error(e);
      alert("Error al guardar: " + e.message);
    }
    setGuardando(false);
  };

  const eliminar = async (sc) => {
    if (!confirm(`¿Dar de baja el SC ${sc.service_center_id}?\n\nSe marcará como vigente_hasta = hoy. Los registros históricos se mantienen.`)) return;
    try {
      const hoy = new Date().toISOString().split("T")[0];
      const { error } = await sb.from("sc_zonas_mx").update({ vigente_hasta: hoy, actualizado_por: "brain" }).eq("id", sc.id);
      if (error) throw error;
      await cargar();
    } catch (e) {
      alert("Error: " + e.message);
    }
  };

  const filtrados = useMemo(() => {
    let res = filtroZona === "todas" ? data : data.filter(d => d.zona === filtroZona);
    if (busqueda) res = res.filter(d => d.service_center_id?.toLowerCase().includes(busqueda.toLowerCase()) || d.ciudad?.toLowerCase().includes(busqueda.toLowerCase()));
    return res;
  }, [data, filtroZona, busqueda]);

  const conteo = data.reduce((acc, d) => { acc[d.zona] = (acc[d.zona] || 0) + 1; return acc; }, {});
  const activos = data.filter(d => !d.vigente_hasta).length;

  if (loading) return <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>Cargando...</div>;

  return (
    <div>
      {/* Detector de huérfanos */}
      {loadingHuerfanos ? (
        <div style={{ background: "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 6, padding: "10px 14px", marginBottom: 14, fontSize: 11, color: "#94a3b8" }}>
          Buscando SCs sin mapeo en viajes recientes...
        </div>
      ) : huerfanos.length > 0 ? (
        <div style={{ background: "#fef2f2", border: "1px solid #fca5a5", borderRadius: 6, padding: 14, marginBottom: 14 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: "#991b1b", marginBottom: 2 }}>
                {huerfanos.length} Service Center{huerfanos.length > 1 ? "s" : ""} sin mapear
              </div>
              <div style={{ fontSize: 11, color: "#7f1d1d" }}>
                Detectados en viajes MX de los últimos 7 días pero ausentes en sc_zonas_mx. Sin zona, esos viajes no calculan pago.
              </div>
            </div>
            <button onClick={detectarHuerfanos}
              style={{ padding: "5px 10px", borderRadius: 4, border: "1px solid #fca5a5", background: "#fff", color: "#991b1b", fontSize: 11, fontWeight: 600, cursor: "pointer" }}>
              Refrescar
            </button>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 8 }}>
            {huerfanos.map(h => (
              <div key={h.sc} style={{ background: "#fff", border: "1px solid #fca5a5", borderRadius: 4, padding: 10, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <div style={{ fontFamily: "monospace", fontSize: 13, fontWeight: 700, color: "#991b1b" }}>{h.sc}</div>
                  <div style={{ fontSize: 10, color: "#7f1d1d", marginTop: 2 }}>
                    {h.viajes} viaje{h.viajes > 1 ? "s" : ""} · desde {String(h.primera).slice(0, 10)}
                  </div>
                </div>
                <button onClick={() => abrirCrear(h.sc)}
                  style={{ padding: "5px 10px", borderRadius: 4, border: "none", background: "#F47B20", color: "#fff", fontSize: 11, fontWeight: 600, cursor: "pointer" }}>
                  Mapear
                </button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div style={{ background: "#ecfdf5", border: "1px solid #a7f3d0", borderRadius: 6, padding: "10px 14px", marginBottom: 14, fontSize: 11, color: "#065f46", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <span>Sin Service Centers huérfanos en últimos 7 días — todos los viajes pueden calcular pago.</span>
          <button onClick={detectarHuerfanos}
            style={{ padding: "4px 10px", borderRadius: 4, border: "1px solid #a7f3d0", background: "#fff", color: "#065f46", fontSize: 10, fontWeight: 600, cursor: "pointer" }}>
            Refrescar
          </button>
        </div>
      )}

      {/* Header con KPIs y acciones */}
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12, flexWrap: "wrap", gap: 10 }}>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>Mapeo Service Center ↔ Zona</div>
            <div style={{ fontSize: 11, color: "#94a3b8" }}>{activos} Service Centers activos · {data.length} totales</div>
          </div>
          <button onClick={() => abrirCrear()}
            style={{ padding: "8px 16px", borderRadius: 4, border: "none", background: "#1a3a6b", color: "#fff", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>
            + Agregar Service Center
          </button>
        </div>
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 10 }}>
          <button onClick={() => setFiltroZona("todas")}
            style={{ padding: "5px 12px", borderRadius: 4, border: `1px solid ${filtroZona === "todas" ? "#1a3a6b" : "#e4e7ec"}`,
              background: filtroZona === "todas" ? "#1a3a6b" : "#fff", color: filtroZona === "todas" ? "#fff" : "#475569",
              fontSize: 11, fontWeight: 600, cursor: "pointer" }}>Todas ({data.length})</button>
          {["L1", "L2", "L3", "L4"].map(z => (
            <button key={z} onClick={() => setFiltroZona(z)}
              style={{ padding: "5px 12px", borderRadius: 4, border: `1px solid ${filtroZona === z ? "#1a3a6b" : "#e4e7ec"}`,
                background: filtroZona === z ? "#1a3a6b" : "#fff", color: filtroZona === z ? "#fff" : "#475569",
                fontSize: 11, fontWeight: 600, cursor: "pointer" }}>{z} ({conteo[z] || 0})</button>
          ))}
        </div>
        <input type="text" placeholder="Buscar por SC o ciudad..." value={busqueda} onChange={e => setBusqueda(e.target.value)}
          style={{ width: "100%", background: "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 4, padding: "6px 10px", fontSize: 12 }} />
      </div>

      {/* Tabla de SCs */}
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, overflow: "hidden" }}>
        {filtrados.length === 0 ? (
          <div style={{ padding: 40, textAlign: "center", color: "#94a3b8", fontSize: 12 }}>Sin resultados</div>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead>
              <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
                <th style={{ padding: "10px 14px", textAlign: "left", fontSize: 11, fontWeight: 600, color: "#475569" }}>SC ID</th>
                <th style={{ padding: "10px 14px", textAlign: "center", fontSize: 11, fontWeight: 600, color: "#475569" }}>Zona</th>
                <th style={{ padding: "10px 14px", textAlign: "left", fontSize: 11, fontWeight: 600, color: "#475569" }}>Ciudad</th>
                <th style={{ padding: "10px 14px", textAlign: "left", fontSize: 11, fontWeight: 600, color: "#475569" }}>Observaciones</th>
                <th style={{ padding: "10px 14px", textAlign: "center", fontSize: 11, fontWeight: 600, color: "#475569" }}>Vigente</th>
                <th style={{ padding: "10px 14px", textAlign: "center", fontSize: 11, fontWeight: 600, color: "#475569" }}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.map(sc => {
                const dadoBaja = sc.vigente_hasta && new Date(sc.vigente_hasta) <= new Date();
                return (
                  <tr key={sc.id} style={{ borderBottom: "1px solid #f0f0f0", opacity: dadoBaja ? 0.5 : 1 }}>
                    <td style={{ padding: "10px 14px", fontFamily: "monospace", fontWeight: 700, color: "#1a3a6b" }}>{sc.service_center_id}</td>
                    <td style={{ padding: "10px 14px", textAlign: "center" }}>
                      <span style={{ fontSize: 11, padding: "3px 10px", borderRadius: 4, background: "#1a3a6b", color: "#fff", fontWeight: 600 }}>{sc.zona}</span>
                    </td>
                    <td style={{ padding: "10px 14px", color: sc.ciudad ? "#1f2937" : "#cbd5e1" }}>{sc.ciudad || "—"}</td>
                    <td style={{ padding: "10px 14px", fontSize: 11, color: "#64748b" }}>{sc.observaciones || ""}</td>
                    <td style={{ padding: "10px 14px", textAlign: "center", fontSize: 11 }}>
                      {dadoBaja ? (
                        <span style={{ color: "#dc2626", fontWeight: 600 }}>Baja {String(sc.vigente_hasta).slice(0, 10)}</span>
                      ) : (
                        <span style={{ color: "#16a34a", fontWeight: 600 }}>Activo</span>
                      )}
                    </td>
                    <td style={{ padding: "10px 14px", textAlign: "center" }}>
                      <button onClick={() => abrirEditar(sc)}
                        style={{ padding: "4px 10px", borderRadius: 4, border: "1px solid #e4e7ec", background: "#fff", color: "#475569", fontSize: 11, fontWeight: 600, cursor: "pointer", marginRight: 4 }}>
                        Editar
                      </button>
                      {!dadoBaja && (
                        <button onClick={() => eliminar(sc)}
                          style={{ padding: "4px 10px", borderRadius: 4, border: "1px solid #fca5a5", background: "#fff", color: "#991b1b", fontSize: 11, fontWeight: 600, cursor: "pointer" }}>
                          Baja
                        </button>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {/* Modal de edición/creación */}
      {modal && (
        <div onClick={cerrarModal}
          style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, background: "rgba(0,0,0,0.5)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000 }}>
          <div onClick={e => e.stopPropagation()}
            style={{ background: "#fff", borderRadius: 8, padding: 20, width: "90%", maxWidth: 480, boxShadow: "0 20px 25px -5px rgba(0,0,0,0.1)" }}>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#1a3a6b", marginBottom: 16 }}>
              {modal.mode === "create" ? "Agregar Service Center" : `Editar ${modal.data.service_center_id}`}
            </div>

            <div style={{ marginBottom: 12 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: "#475569", display: "block", marginBottom: 4 }}>Service Center ID *</label>
              <input type="text" value={modal.data.service_center_id} disabled={modal.mode === "edit"}
                onChange={e => setModal({ ...modal, data: { ...modal.data, service_center_id: e.target.value.toUpperCase() } })}
                placeholder="Ej: SMX7"
                style={{ width: "100%", background: modal.mode === "edit" ? "#f1f5f9" : "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 4, padding: "8px 10px", fontSize: 12, fontFamily: "monospace", fontWeight: 600 }} />
            </div>

            <div style={{ marginBottom: 12 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: "#475569", display: "block", marginBottom: 4 }}>Zona *</label>
              <div style={{ display: "flex", gap: 6 }}>
                {["L1", "L2", "L3", "L4"].map(z => (
                  <button key={z} onClick={() => setModal({ ...modal, data: { ...modal.data, zona: z } })}
                    style={{ flex: 1, padding: "8px 0", borderRadius: 4, border: `1px solid ${modal.data.zona === z ? "#1a3a6b" : "#e4e7ec"}`,
                      background: modal.data.zona === z ? "#1a3a6b" : "#fff", color: modal.data.zona === z ? "#fff" : "#475569",
                      fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
                    {z}
                  </button>
                ))}
              </div>
            </div>

            <div style={{ marginBottom: 12 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: "#475569", display: "block", marginBottom: 4 }}>Ciudad</label>
              <input type="text" value={modal.data.ciudad || ""}
                onChange={e => setModal({ ...modal, data: { ...modal.data, ciudad: e.target.value } })}
                placeholder="Ej: Pachuca"
                style={{ width: "100%", background: "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 4, padding: "8px 10px", fontSize: 12 }} />
            </div>

            <div style={{ marginBottom: 12 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: "#475569", display: "block", marginBottom: 4 }}>Vigente desde</label>
              <input type="date" value={modal.data.vigente_desde}
                onChange={e => setModal({ ...modal, data: { ...modal.data, vigente_desde: e.target.value } })}
                style={{ width: "100%", background: "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 4, padding: "8px 10px", fontSize: 12 }} />
            </div>

            <div style={{ marginBottom: 16 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: "#475569", display: "block", marginBottom: 4 }}>Observaciones</label>
              <textarea value={modal.data.observaciones || ""}
                onChange={e => setModal({ ...modal, data: { ...modal.data, observaciones: e.target.value } })}
                placeholder="Notas internas (opcional)"
                style={{ width: "100%", background: "#f8fafc", border: "1px solid #e4e7ec", borderRadius: 4, padding: "8px 10px", fontSize: 12, fontFamily: "inherit", minHeight: 60, resize: "vertical" }} />
            </div>

            <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
              <button onClick={cerrarModal} disabled={guardando}
                style={{ padding: "8px 16px", borderRadius: 4, border: "1px solid #e4e7ec", background: "#fff", color: "#475569", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>
                Cancelar
              </button>
              <button onClick={guardar} disabled={guardando}
                style={{ padding: "8px 16px", borderRadius: 4, border: "none", background: guardando ? "#94a3b8" : "#1a3a6b", color: "#fff", fontSize: 12, fontWeight: 600, cursor: guardando ? "wait" : "pointer" }}>
                {guardando ? "Guardando..." : modal.mode === "create" ? "Crear" : "Guardar cambios"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── Config: Matriz Auxiliares ─────────────────────────────────────────────
function ConfigMatrizAuxiliares() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { cargar(); }, []);
  const cargar = async () => {
    setLoading(true);
    try {
      const { data: m } = await sb.from("matriz_ayudantes_autorizados").select("*").order("prioridad", { ascending: false });
      setData(m || []);
    } catch (e) { console.error(e); }
    setLoading(false);
  };

  if (loading) return <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>Cargando...</div>;

  return (
    <div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>Matriz de Auxiliares Autorizados</div>
        <div style={{ fontSize: 11, color: "#94a3b8" }}>Define qué SC + vehículo + zona pueden cobrar el ayudante de $300 MXN</div>
      </div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14 }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>SC</th>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Vehículo</th>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Zona</th>
              <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Estado</th>
              <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Monto</th>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, color: "#64748b", fontWeight: 600 }}>Observaciones</th>
            </tr>
          </thead>
          <tbody>
            {data.map(r => (
              <tr key={r.id} style={{ borderBottom: "1px solid #f0f0f0" }}>
                <td style={{ padding: "8px 10px" }}>{r.service_center_id || <span style={{ color: "#94a3b8" }}>TODOS</span>}</td>
                <td style={{ padding: "8px 10px" }}>{r.vehiculo_tipo || <span style={{ color: "#94a3b8" }}>TODOS</span>}</td>
                <td style={{ padding: "8px 10px" }}>{r.zona || <span style={{ color: "#94a3b8" }}>TODAS</span>}</td>
                <td style={{ padding: "8px 10px", textAlign: "center" }}>
                  <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 4, background: r.autorizado ? "#dcfce7" : "#fee2e2", color: r.autorizado ? "#166534" : "#991b1b", fontWeight: 600 }}>
                    {r.autorizado ? "AUTORIZADO" : "NO AUTORIZADO"}
                  </span>
                </td>
                <td style={{ padding: "8px 10px", textAlign: "right", fontWeight: 600, color: r.autorizado ? "#16a34a" : "#94a3b8" }}>${r.monto}</td>
                <td style={{ padding: "8px 10px", color: "#64748b", fontSize: 11 }}>{r.observaciones || "—"}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── Config: Reglas NS ─────────────────────────────────────────────────────
function ConfigReglasNS() {
  return (
    <div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14, marginBottom: 14 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>Reglas de Nivel de Servicio (NS)</div>
        <div style={{ fontSize: 11, color: "#94a3b8" }}>Premio o multa según el rendimiento del chofer</div>
      </div>
      <div style={{ background: "#fff", border: "1px solid #e4e7ec", borderRadius: 6, padding: 14 }}>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
              <th style={{ padding: "10px", textAlign: "left", fontSize: 11, color: "#475569", fontWeight: 600 }}>Categoría</th>
              <th style={{ padding: "10px", textAlign: "left", fontSize: 11, color: "#475569", fontWeight: 600 }}>Condición</th>
              <th style={{ padding: "10px", textAlign: "right", fontSize: 11, color: "#475569", fontWeight: 600 }}>Ajuste</th>
            </tr>
          </thead>
          <tbody>
            <tr style={{ borderBottom: "1px solid #f0f0f0" }}>
              <td style={{ padding: "10px" }}>
                <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 4, background: "#dcfce7", color: "#166534", fontWeight: 600 }}>Excelente</span>
              </td>
              <td style={{ padding: "10px", color: "#64748b" }}>NS ≥ 99.5% Y No visitado &lt; 0.5%</td>
              <td style={{ padding: "10px", textAlign: "right", fontWeight: 700, color: "#16a34a" }}>+5%</td>
            </tr>
            <tr style={{ borderBottom: "1px solid #f0f0f0" }}>
              <td style={{ padding: "10px" }}>
                <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 4, background: "#f1f5f9", color: "#475569", fontWeight: 600 }}>Aceptable</span>
              </td>
              <td style={{ padding: "10px", color: "#64748b" }}>NS entre 95% y 99.49%</td>
              <td style={{ padding: "10px", textAlign: "right", fontWeight: 700, color: "#475569" }}>0%</td>
            </tr>
            <tr style={{ borderBottom: "1px solid #f0f0f0" }}>
              <td style={{ padding: "10px" }}>
                <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 4, background: "#fed7aa", color: "#9a3412", fontWeight: 600 }}>Deficiente</span>
              </td>
              <td style={{ padding: "10px", color: "#64748b" }}>NS &lt; 95%</td>
              <td style={{ padding: "10px", textAlign: "right", fontWeight: 700, color: "#F47B20" }}>-3%</td>
            </tr>
            <tr style={{ borderBottom: "1px solid #f0f0f0" }}>
              <td style={{ padding: "10px" }}>
                <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 4, background: "#fee2e2", color: "#991b1b", fontWeight: 600 }}>Crítico</span>
              </td>
              <td style={{ padding: "10px", color: "#64748b" }}>No visitado &gt; 10%</td>
              <td style={{ padding: "10px", textAlign: "right", fontWeight: 700, color: "#c0392b" }}>NO PAGO</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
}



// ═══════════════════════════════════════════════════════════════════════════
// INDICADORES OPERACIONALES MX — Pool Mercado Libre
// ═══════════════════════════════════════════════════════════════════════════

// SheetJS lazy-load para descarga Excel
const cargarSheetJS = () => new Promise((resolve, reject) => {
  if (window.XLSX) return resolve(window.XLSX);
  const s = document.createElement('script');
  s.src = 'https://cdn.sheetjs.com/xlsx-0.20.1/package/dist/xlsx.full.min.js';
  s.onload = () => resolve(window.XLSX);
  s.onerror = reject;
  document.head.appendChild(s);
});

async function descargarExcelMeli(filas, nombreArchivo, nombreHoja = "Datos") {
  if (!filas || filas.length === 0) {
    alert("No hay datos para descargar");
    return;
  }
  try {
    const XLSX = await cargarSheetJS();
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(filas);
    XLSX.utils.book_append_sheet(wb, ws, nombreHoja.slice(0, 31));
    XLSX.writeFile(wb, `${nombreArchivo}.xlsx`);
  } catch (e) {
    console.error("Error descargando Excel:", e);
    alert("No se pudo descargar el Excel: " + (e.message || e));
  }
}

// Helper para nombres de meses en español
const NOMBRES_MES = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", 
                     "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

function diasDelMes(anio, mes) {
  return new Date(anio, mes, 0).getDate();
}

// Calcula el rango {desde, hasta} de un mes seleccionado.
// Regla: si el mes ya terminó → mes completo. Si es el actual → hasta ayer (CURRENT_DATE - 1).
function rangoMesGlobal(mesGlobal) {
  const yyyy = mesGlobal.anio;
  const mm = String(mesGlobal.mes).padStart(2, '0');
  const desde = `${yyyy}-${mm}-01`;
  
  const hoy = new Date();
  const esMesActual = mesGlobal.anio === hoy.getFullYear() && mesGlobal.mes === (hoy.getMonth() + 1);
  
  let hasta;
  if (esMesActual) {
    // Mes en curso: hasta ayer
    const ayer = new Date(hoy);
    ayer.setDate(ayer.getDate() - 1);
    hasta = ayer.toISOString().slice(0, 10);
  } else {
    // Mes pasado: mes completo
    const ultDia = diasDelMes(mesGlobal.anio, mesGlobal.mes);
    hasta = `${yyyy}-${mm}-${String(ultDia).padStart(2, '0')}`;
  }
  return { desde, hasta };
}

function IndicadoresOperacionalesMX({ usuario }) {
  const [vista, setVista] = useState("resumen_kpi");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [resumen, setResumen] = useState(null);
  const [drivers, setDrivers] = useState([]);
  const [vehiculos, setVehiculos] = useState([]);
  const [scs, setSCs] = useState([]);
  const [scores, setScores] = useState([]);
  const [modal, setModal] = useState(null);
  
  // ─── SELECTOR GLOBAL DE MES ─────────────────────────────────────────────
  const [mesesDisponibles, setMesesDisponibles] = useState([]);
  const [mesGlobal, setMesGlobal] = useState(() => {
    const hoy = new Date();
    return { anio: hoy.getFullYear(), mes: hoy.getMonth() + 1 };
  });

  // Estado para vista detalle in-place (driver o vehículo)
  const [detalle, setDetalle] = useState(null); // { tipo: 'driver'|'vehiculo', registro: {...} }

  // Cargar meses disponibles UNA sola vez al montar
  useEffect(() => {
    (async () => {
      try {
        const { data, error } = await sb.rpc("get_meses_con_datos_meli");
        if (error) throw error;
        setMesesDisponibles(data || []);
        // Si no hay datos del mes actual, ir al mes más reciente
        const hoy = new Date();
        const anioActual = hoy.getFullYear(), mesActual = hoy.getMonth() + 1;
        const tieneActual = (data || []).some(m => m.anio === anioActual && m.mes === mesActual);
        if (!tieneActual && data && data.length > 0) {
          setMesGlobal({ anio: data[0].anio, mes: data[0].mes });
        }
      } catch (e) {
        console.error("Error cargando meses:", e);
      }
    })();
  }, []);

  // Recargar TODOS los datos cuando cambia el mes
  useEffect(() => {
    let alive = true;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const { desde, hasta } = rangoMesGlobal(mesGlobal);
        
        const [r1, r2, r3, r4, r5] = await Promise.all([
          sb.from("vw_meli_dashboard_resumen").select("*").maybeSingle(),
          sb.rpc("get_inventario_drivers_mes", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_inventario_vehiculos_mes", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_ciclo_aceptacion_sc", { fecha_desde: desde, fecha_hasta: hasta }),
          sb.rpc("get_score_compromiso", { fecha_desde: desde, fecha_hasta: hasta }),
        ]);
        if (!alive) return;
        if (r1.error || r2.error || r3.error || r4.error || r5.error) {
          throw new Error(r1.error?.message || r2.error?.message || r3.error?.message || r4.error?.message || r5.error?.message);
        }
        setResumen(r1.data);
        setDrivers((r2.data || []).sort((a, b) => (b.viajes_total || 0) - (a.viajes_total || 0)));
        setVehiculos((r3.data || []).sort((a, b) => (b.viajes_total || 0) - (a.viajes_total || 0)));
        setSCs((r4.data || []).sort((a, b) => (b.ofrecidas || 0) - (a.ofrecidas || 0)));
        setScores((r5.data || []).sort((a, b) => (b.score_total || 0) - (a.score_total || 0)));
      } catch (e) {
        if (alive) setError(e.message || "Error cargando datos");
      } finally {
        if (alive) setLoading(false);
      }
    })();
    return () => { alive = false; };
  }, [mesGlobal.anio, mesGlobal.mes]);

  // Tabs: orden ahora con Hallazgos AL FINAL
  const tabs = [
    { id: "resumen_kpi", label: "Resumen KPI", desc: "Día anterior · vista ejecutiva" },
    { id: "inventario", label: "Inventario", desc: "Drivers, vehículos, fantasmas" },
    { id: "ciclo",      label: "Ciclo de aceptación", desc: "Embudo ofrecidas → ejecutadas" },
    { id: "score",      label: "Score de compromiso", desc: "Calificación 0-100 por driver" },
    { id: "hallazgos",  label: "Hallazgos", desc: "Lo más crítico para revisar" },
  ];

  if (loading) {
    return (
      <div className="pg">
        <div className="sec-title">Indicadores Operacionales MX</div>
        <div className="sec-sub">Pool Mercado Libre · Bigticket México</div>
        <div className="form-card" style={{ textAlign: "center", padding: 40, color: "#666" }}>
          Cargando indicadores…
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="pg">
        <div className="sec-title">Indicadores Operacionales MX</div>
        <div className="sec-sub">Pool Mercado Libre · Bigticket México</div>
        <div className="form-card" style={{ background: "#fef2f2", border: "1px solid #fecaca" }}>
          <div style={{ fontSize: 13, fontWeight: 600, color: "#991b1b", marginBottom: 6 }}>
            No se pudo cargar la información
          </div>
          <div style={{ fontSize: 12, color: "#7f1d1d", lineHeight: 1.6 }}>
            {error}
            <br /><br />
            <strong>Causa probable:</strong> las vistas <code>vw_meli_*</code> aún no fueron creadas en Supabase.
          </div>
        </div>
      </div>
    );
  }

  // Vista detalle ocupa toda la pantalla del módulo
  if (detalle) {
    return (
      <PoolMeliDetalleRegistro 
        tipo={detalle.tipo} 
        registro={detalle.registro} 
        onVolver={() => setDetalle(null)} 
      />
    );
  }

  return (
    <div style={{ padding: 0 }}>
      <div style={{ background: "#fff", borderBottom: "1px solid #e4e7ec", padding: "12px 24px" }}>
        <div style={{ fontSize: 18, fontWeight: 700, color: "#1a3a6b", marginBottom: 4 }}>
          Indicadores Operacionales MX
        </div>
        <div style={{ fontSize: 12, color: "#64748b", marginBottom: 10 }}>
          Pool Mercado Libre · cruce de 6 fuentes operativas
        </div>
        <div style={{ display: "flex", gap: 0, borderBottom: "2px solid #e4e7ec", marginLeft: -8, flexWrap: "wrap", alignItems: "flex-end", justifyContent: "space-between" }}>
          <div style={{ display: "flex", gap: 0, flexWrap: "wrap" }}>
            {tabs.map(t => (
              <button key={t.id} onClick={() => setVista(t.id)}
                style={{
                  background: "transparent", border: "none", padding: "10px 16px",
                  fontSize: 13, fontWeight: 600, cursor: "pointer", color: vista === t.id ? "#1a3a6b" : "#64748b",
                  borderBottom: vista === t.id ? "2px solid #1a3a6b" : "2px solid transparent",
                  marginBottom: -2,
                }}>
                <div>{t.label}</div>
                <div style={{ fontSize: 10, color: "#94a3b8", fontWeight: 400, marginTop: 2 }}>{t.desc}</div>
              </button>
            ))}
          </div>
          {/* Dropdown global de mes (no aplica en Resumen KPI) */}
          {vista !== "resumen_kpi" && (
          <div style={{ display: "flex", alignItems: "center", gap: 8, paddingBottom: 8 }}>
            <span style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5 }}>
              Período:
            </span>
            <select 
              value={`${mesGlobal.anio}-${mesGlobal.mes}`}
              onChange={(e) => {
                const [a, m] = e.target.value.split('-').map(Number);
                setMesGlobal({ anio: a, mes: m });
              }}
              style={{
                padding: "6px 12px", fontSize: 13, fontWeight: 600, borderRadius: 6,
                border: "1px solid #cbd5e1", background: "#fff", color: "#1a3a6b",
                cursor: "pointer", fontFamily: "'Geist', sans-serif", outline: "none",
              }}>
              {mesesDisponibles.map(m => (
                <option key={`${m.anio}-${m.mes}`} value={`${m.anio}-${m.mes}`}>
                  {NOMBRES_MES[m.mes - 1]} {m.anio} ({m.dias_con_datos} días)
                </option>
              ))}
            </select>
          </div>
          )}
        </div>
      </div>

      {vista === "resumen_kpi" && <PoolMeliResumenKPI />}
      {vista === "inventario" && <PoolMeliInventario drivers={drivers} vehiculos={vehiculos} resumen={resumen} setModal={setModal} setDetalle={setDetalle} mesGlobal={mesGlobal} />}
      {vista === "ciclo"      && <PoolMeliCiclo scs={scs} resumen={resumen} setModal={setModal} mesGlobal={mesGlobal} />}
      {vista === "score"      && <PoolMeliScore scores={scores} resumen={resumen} mesGlobal={mesGlobal} />}
      {vista === "hallazgos"  && <PoolMeliHallazgos drivers={drivers} vehiculos={vehiculos} scs={scs} scores={scores} resumen={resumen} setModal={setModal} setVista={setVista} mesGlobal={mesGlobal} />}

      {modal && <MeliModal modal={modal} onClose={() => setModal(null)} />}
    </div>
  );
}

// ── MODAL ──────────────────────────────────────────────────────────────────
function MeliModal({ modal, onClose }) {
  const [busqueda, setBusqueda] = useState("");
  const filas = modal.filas || [];
  const columnas = modal.columnas || (filas[0] ? Object.keys(filas[0]) : []);

  const filtradas = useMemo(() => {
    let res = filas;
    if (modal.filtros) {
      Object.entries(modal.filtros).forEach(([col, valores]) => {
        if (valores && valores.length > 0) {
          res = res.filter(r => valores.includes(r[col]));
        }
      });
    }
    if (busqueda.trim()) {
      const q = busqueda.toLowerCase().trim();
      res = res.filter(row =>
        columnas.some(c => {
          const val = row[c];
          if (val == null) return false;
          return String(val).toLowerCase().includes(q);
        })
      );
    }
    return res;
  }, [busqueda, filas, columnas, modal.filtros]);

  return (
    <div onClick={onClose}
      style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
        background: "rgba(15,23,42,0.55)", zIndex: 9999,
        display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div onClick={e => e.stopPropagation()}
        style={{ background: "#fff", borderRadius: 12, width: "100%", maxWidth: 1200,
          maxHeight: "92vh", display: "flex", flexDirection: "column", overflow: "hidden",
          boxShadow: "0 20px 50px rgba(0,0,0,0.25)" }}>
        <div style={{ padding: "14px 20px", borderBottom: "1px solid #e4e7ec",
          display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 700, color: "#1a3a6b" }}>{modal.titulo}</div>
            <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>
              {filtradas.length} {filtradas.length === 1 ? "registro" : "registros"}
              {(busqueda || modal.filtros) && ` (de ${filas.length} totales)`}
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <input type="text" placeholder="Buscar..." value={busqueda}
              onChange={e => setBusqueda(e.target.value)}
              style={{ width: 240, padding: "7px 10px", border: "1px solid #d0d5dd",
                borderRadius: 6, fontSize: 12, fontFamily: "'Geist', sans-serif" }} />
            <button onClick={() => descargarExcelMeli(filtradas, modal.nombreArchivo || "export_meli", modal.titulo.slice(0, 31))}
              className="btn-orange" style={{ padding: "7px 12px", fontSize: 12 }}>
              Descargar Excel
            </button>
            <button onClick={onClose}
              style={{ background: "transparent", border: "none", fontSize: 22, cursor: "pointer",
                color: "#64748b", padding: "0 4px", lineHeight: 1 }}>×</button>
          </div>
        </div>

        {modal.filtros_ui && (
          <div style={{ padding: "10px 20px", background: "#f8fafc", borderBottom: "1px solid #e4e7ec" }}>
            {modal.filtros_ui}
          </div>
        )}

        <div style={{ flex: 1, overflow: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 12 }}>
            <thead style={{ position: "sticky", top: 0, background: "#f8fafc", zIndex: 1 }}>
              <tr style={{ borderBottom: "2px solid #e2e8f0" }}>
                {columnas.map(c => (
                  <th key={c} style={{ textAlign: "left", padding: "8px 12px",
                    fontSize: 10, fontWeight: 700, color: "#475569",
                    textTransform: "uppercase", letterSpacing: 0.5,
                    whiteSpace: "nowrap" }}>{c}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtradas.length === 0 && (
                <tr><td colSpan={columnas.length} style={{ padding: 30, textAlign: "center", color: "#94a3b8" }}>
                  Sin resultados
                </td></tr>
              )}
              {filtradas.map((row, i) => (
                <tr key={i} style={{ borderBottom: "1px solid #f1f5f9" }}>
                  {columnas.map(c => (
                    <td key={c} style={{ padding: "7px 12px", color: "#1a1a1a", whiteSpace: "nowrap" }}>
                      {row[c] === null || row[c] === undefined ? "—"
                        : typeof row[c] === "boolean" ? (row[c] ? "Sí" : "No")
                        : String(row[c])}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ── HELPERS visuales ───────────────────────────────────────────────────────
function PoolMeliKpi({ label, value, sublabel, color = "#1a3a6b", danger = false, warn = false, onClick = null }) {
  const bg = danger ? "#fef2f2" : warn ? "#fffbeb" : "#fff";
  const border = danger ? "#fecaca" : warn ? "#fde68a" : "#e4e7ec";
  const valColor = danger ? "#991b1b" : warn ? "#92400e" : color;
  const clickable = !!onClick;
  return (
    <div onClick={onClick}
      style={{ background: bg, border: `1px solid ${border}`, borderRadius: 12, padding: 16,
        cursor: clickable ? "pointer" : "default", transition: "all 0.15s",
        ...(clickable ? { boxShadow: "0 1px 2px rgba(0,0,0,0.03)" } : {}) }}
      onMouseEnter={e => clickable && (e.currentTarget.style.boxShadow = "0 4px 12px rgba(26,58,107,0.12)")}
      onMouseLeave={e => clickable && (e.currentTarget.style.boxShadow = "0 1px 2px rgba(0,0,0,0.03)")}>
      <div style={{ fontSize: 11, color: "#64748b", textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6, fontWeight: 600,
        display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span>{label}</span>
        {clickable && <span style={{ fontSize: 9, color: "#94a3b8" }}>VER →</span>}
      </div>
      <div style={{ fontSize: 28, fontWeight: 700, color: valColor, lineHeight: 1, marginBottom: 4 }}>{value}</div>
      {sublabel && <div style={{ fontSize: 11, color: "#94a3b8" }}>{sublabel}</div>}
    </div>
  );
}

